# ─────────────────────────────────────────────────────────────────────────────
# CORPUS LOADER
# ─────────────────────────────────────────────────────────────────────────────

class ScriptureCorpusLoader:
    """
    Loads and segments the NIV Scripture corpus from the provided PDF text.
    Segments corpus into: books → chapters → passages (verse groups).

    Production: replace pdf_text with direct PDF extraction output from
    the NIV-Bible.pdf uploaded at session inception.
    """

    def __init__(self, corpus_text: str):
        self.raw_text   = corpus_text
        self.books:     Dict[str, str]        = {}
        self.passages:  List[Dict]            = []
        self._parse()

    def _parse(self) -> None:
        """
        Parse raw NIV text into book-level segments.
        Identifies book boundaries by known book names.
        """
        book_names = list(BOOK_DOMAIN_MAP.keys())
        # Sort longest first to avoid partial matches
        book_names_sorted = sorted(book_names, key=len, reverse=True)

        current_book  = None
        current_lines = []

        for line in self.raw_text.split("\n"):
            stripped = line.strip()
            matched  = False
            for book in book_names_sorted:
                if stripped.startswith(book) and len(stripped) < len(book) + 5:
                    if current_book and current_lines:
                        self.books[current_book] = "\n".join(current_lines)
                    current_book  = book
                    current_lines = []
                    matched = True
                    break
            if not matched and current_book:
                current_lines.append(stripped)

        if current_book and current_lines:
            self.books[current_book] = "\n".join(current_lines)

        log.info(f"Corpus parsed: {len(self.books)} books identified.")
        self._extract_passages()

    def _extract_passages(self) -> None:
        """
        Extract verse-level passages from each book.
        A passage = contiguous verse group of >= MQ_MIN_PASSAGE_LEN words.
        """
        for book, text in self.books.items():
            domain    = BOOK_DOMAIN_MAP.get(book, "wisdom")
            sentences = re.split(r'(?<=[.!?])\s+', text)
            buffer    = []
            for sent in sentences:
                buffer.append(sent)
                joined = " ".join(buffer)
                if len(joined.split()) >= MQ_MIN_PASSAGE_LEN:
                    self.passages.append({
                        "book":    book,
                        "domain":  domain,
                        "text":    joined,
                        "words":   len(joined.split()),
                    })
                    buffer = []

        log.info(f"Passages extracted: {len(self.passages)} total.")

    def get_passages_by_book(self, book: str) -> List[Dict]:
        return [p for p in self.passages if p["book"] == book]

    def sample_passages(self, n: int = TB_SEED_PER_BOOK) -> List[Dict]:
        """Random sample of n passages per book."""
        rng    = np.random.default_rng(seed=42)
        result = []
        for book in self.books:
            book_passages = self.get_passages_by_book(book)
            if not book_passages:
                continue
            k = min(n, len(book_passages))
            idx = rng.choice(len(book_passages), size=k, replace=False)
            result.extend([book_passages[i] for i in idx])
        return result


# ─────────────────────────────────────────────────────────────────────────────
# MORAL PASSAGE CLASSIFIER
# ─────────────────────────────────────────────────────────────────────────────

class MoralPassageClassifier:
    """
    Classifies passages by moral dimension using keyword proximity scoring.

    Production: replace with fine-tuned sentence classifier trained on
    annotated moral reasoning dataset derived from Scripture.

    Output: dimension label ∈ MORAL_DIMENSIONS + confidence score ∈ [0,1]
    """

    def classify(self, passage_text: str) -> Tuple[str, float]:
        """Returns (dimension, confidence) for the dominant moral dimension."""
        text_lower = passage_text.lower()
        scores     = {}
        for dim, keywords in MORAL_KEYWORDS.items():
            hits       = sum(1 for kw in keywords if kw in text_lower)
            scores[dim] = hits / len(keywords)

        best_dim   = max(scores, key=scores.get)
        best_score = scores[best_dim]
        # Normalize confidence
        total      = sum(scores.values()) + 1e-8
        confidence = best_score / total
        return best_dim, float(np.clip(confidence, 0.0, 1.0))

    def classify_batch(self, passages: List[Dict]) -> List[Dict]:
        """Classify a list of passages, adding dimension and confidence fields."""
        result = []
        for p in passages:
            dim, conf = self.classify(p["text"])
            result.append({**p, "moral_dimension": dim, "confidence": conf})
        return result


# ─────────────────────────────────────────────────────────────────────────────
# SEMANTIC EMBEDDER  (NIV-corpus)
# ─────────────────────────────────────────────────────────────────────────────

class ScriptureEmbedder:
    """
    Produces deterministic semantic embeddings from passage text.
    Matches SymbolicMemory._semantic_embed() in G_enhanced:
        embed_dim = 16, hash-seeded RNG, unit-normalized.

    Production: replace with sentence-transformers model fine-tuned on
    Scripture for richer semantic representations.
    """

    def __init__(self, embed_dim: int = EMBED_DIM):
        self.embed_dim   = embed_dim
        self._cache: Dict[str, np.ndarray] = {}

    def embed(self, text: str) -> np.ndarray:
        if text in self._cache:
            return self._cache[text]
        rng   = np.random.RandomState(abs(hash(text)) % (2**31))
        vec   = rng.randn(self.embed_dim).astype(np.float32)
        vec  /= (np.linalg.norm(vec) + 1e-8)
        self._cache[text] = vec
        return vec

    def embed_batch(self, texts: List[str]) -> np.ndarray:
        """Returns (N, embed_dim) array."""
        return np.stack([self.embed(t) for t in texts])

    def centroid(self, texts: List[str]) -> np.ndarray:
        """Mean embedding (unit-normalized) for a group of texts."""
        vecs = self.embed_batch(texts)
        mean = vecs.mean(axis=0)
        return mean / (np.linalg.norm(mean) + 1e-8)


# ─────────────────────────────────────────────────────────────────────────────
# MQ FOUNDATION SEEDER
# ─────────────────────────────────────────────────────────────────────────────

class MQFoundationSeeder:
    """
    Seeds the Moral Quotient training signal from the NIV corpus.

    Produces MQ_reference: shape (6, embed_dim)
    One centroid embedding per moral dimension.

    G_enhanced.MultipleIntelligences uses this reference to score
    MQ as cosine proximity to the dimension centroids, replacing
    the default proxy computation.

    Computation notation:
        MQ_reference[d] = centroid( { embed(p) : p ∈ P_moral, class(p) = d } )
        MQ_score(task)  = mean( cosine_sim( embed(task), MQ_reference[d] )
                          for d ∈ D_moral )
    """

    def __init__(self, embedder: ScriptureEmbedder,
                 classifier: MoralPassageClassifier):
        self.embedder   = embedder
        self.classifier = classifier
        self.mq_reference: Optional[np.ndarray] = None   # (6, embed_dim)
        self.dimension_counts: Dict[str, int]    = {}

    def seed(self, passages: List[Dict]) -> np.ndarray:
        """
        Classify passages by moral dimension, compute per-dimension centroids.
        Returns MQ_reference array of shape (6, EMBED_DIM).
        """
        classified = self.classifier.classify_batch(passages)

        # Group by dimension
        dim_texts: Dict[str, List[str]] = {d: [] for d in MORAL_DIMENSIONS}
        for p in classified:
            dim = p["moral_dimension"]
            if dim in dim_texts:
                dim_texts[dim].append(p["text"])

        # Compute centroid per dimension
        centroids = []
        for dim in MORAL_DIMENSIONS:
            texts = dim_texts[dim]
            self.dimension_counts[dim] = len(texts)
            if texts:
                centroid = self.embedder.centroid(texts)
            else:
                # Fallback: seed from dimension name itself
                centroid = self.embedder.embed(f"biblical {dim} righteousness")
                log.warning(f"  MQ dimension '{dim}' had no passages — "
                             f"seeded from label embedding.")
            centroids.append(centroid)

        self.mq_reference = np.stack(centroids)   # (6, embed_dim)

        log.info("MQ Foundation seeded:")
        for i, dim in enumerate(MORAL_DIMENSIONS):
            log.info(f"  [{i}] {dim:16s}: "
                     f"{self.dimension_counts.get(dim, 0):4d} passages | "
                     f"centroid norm = "
                     f"{np.linalg.norm(self.mq_reference[i]):.4f}")

        return self.mq_reference

    def score(self, task_text: str) -> float:
        """
        Score a task description against the MQ reference centroids.
        Returns MQ_score ∈ [0, 1].
        """
        if self.mq_reference is None:
            raise RuntimeError("MQFoundationSeeder.seed() must be called first.")
        task_embed = self.embedder.embed(task_text)
        sims = np.array([
            float(np.dot(task_embed, self.mq_reference[i]))
            for i in range(len(MORAL_DIMENSIONS))
        ])
        # Cosine similarity ∈ [-1, 1] → normalize to [0, 1]
        return float(np.clip((sims.mean() + 1.0) / 2.0, 0.0, 1.0))


# ─────────────────────────────────────────────────────────────────────────────
# TB FOUNDATION SEEDER
# ─────────────────────────────────────────────────────────────────────────────

class TBFoundationSeeder:
    """
    Pre-seeds G_enhanced.SymbolicMemory with Scripture embeddings
    before any task episode runs.

    Implements:
        For each passage p ∈ sample(C_NIV, TB_SEED_PER_BOOK):
            SymbolicMemory.bind( canonical_label(p), episode_id=-1 )

    episode_id = -1 marks all pre-episode bindings as foundational.
    Subsequent task-episode bindings (episode_id >= 0) build on top.

    Result at inception:
        |TB.memory| > 0
        TB_density  > 0  (anchored by scriptural semantic coherence)
    """

    def seed(self, symbolic_memory, passages: List[Dict]) -> int:
        """
        Bind sampled passages into SymbolicMemory.
        symbolic_memory: instance of G_enhanced.SymbolicMemory
        Returns count of concepts bound.
        """
        count = 0
        for p in passages:
            # Canonical label: "Book::domain::passage_index"
            label = (f"{p['book']}::{p['domain']}::"
                     f"p{count}")
            symbolic_memory.bind(concept=label, episode_id=-1)
            count += 1

        log.info(f"TB Foundation seeded: {count} passages bound.")
        log.info(f"  TB_density at inception: "
                 f"{symbolic_memory.tb_density:.4f}")
        log.info(f"  TB memory size:          "
                 f"{len(symbolic_memory.memory)} embeddings")
        return count


# ─────────────────────────────────────────────────────────────────────────────
# HKS FOUNDATION SEEDER
# ─────────────────────────────────────────────────────────────────────────────

class HKSFoundationSeeder:
    """
    Pre-constructs the HKS root layer from the Scripture domain structure.

    Implements:
        HKS.graph.add_node("root::Scripture", level=0, type="root")
        For each d ∈ D_scripture:
            HKS.graph.add_node(f"domain::{d}", level=1, type="domain")
            HKS.graph.add_edge("root::Scripture", f"domain::{d}", weight=1.0)

    Result at inception:
        HKS.depth   = 0.4  (level 2 normalized by 5.0)
        HKS.graph   = pre-structured, ready for task nodes as children
    """

    ROOT_NODE = "root::Scripture"

    def seed(self, hks) -> None:
        """
        hks: instance of G_enhanced.HierarchicalKnowledgeStructure
        Adds root and primary domain nodes before any task is ingested.
        """
        # Add root node
        hks.graph.add_node(
            self.ROOT_NODE,
            level=0,
            type="root",
            source="NIV_Scripture",
        )

        # Add six primary domain nodes
        for domain in SCRIPTURE_DOMAINS:
            domain_node = f"domain::{domain}"
            hks.graph.add_node(
                domain_node,
                level=1,
                type="domain",
                source="NIV_Scripture",
            )
            hks.graph.add_edge(
                self.ROOT_NODE,
                domain_node,
                weight=1.0,
            )

        # Add book-level nodes (level 2) under each domain
        for book, domain in BOOK_DOMAIN_MAP.items():
            book_node   = f"book::{book}"
            domain_node = f"domain::{domain}"
            hks.graph.add_node(
                book_node,
                level=2,
                type="book",
                source="NIV_Scripture",
            )
            if hks.graph.has_node(domain_node):
                hks.graph.add_edge(domain_node, book_node, weight=0.8)

        depth = hks.depth
        log.info(f"HKS Foundation seeded:")
        log.info(f"  Root node:    '{self.ROOT_NODE}'")
        log.info(f"  Domain nodes: {len(SCRIPTURE_DOMAINS)}")
        log.info(f"  Book nodes:   {len(BOOK_DOMAIN_MAP)}")
        log.info(f"  HKS depth at inception: {depth:.4f}")
        log.info(f"  Graph nodes:  {hks.graph.number_of_nodes()}")
        log.info(f"  Graph edges:  {hks.graph.number_of_edges()}")


# ─────────────────────────────────────────────────────────────────────────────
# FOUNDATION INITIALIZER  —  MAIN ENTRY POINT
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class FoundationState:
    """
    State object returned by FoundationInitializer.run().
    Carries all seeded reference data for G_enhanced to use.
    """
    mq_reference:      np.ndarray          # (6, embed_dim) — MQ centroids
    mq_seeder:         MQFoundationSeeder  # scorer for runtime MQ computation
    tb_passages_bound: int                 # count of TB pre-bindings
    hks_nodes_added:   int                 # count of HKS nodes at inception
    dimension_counts:  Dict[str, int]      # passages per moral dimension
    initialized_at:    float = field(
                           default_factory=time.time)


class FoundationInitializer:
    """
    Inception-layer module for ai2agi G_enhanced.

    MUST be called once, before GEnhanced.generate_tensors(),
    to consecrate the input foundations of MQ, TB, and HKS.

    Usage:
        corpus_text = open("NIV_Bible.txt").read()   # or from PDF extraction
        fi = FoundationInitializer(corpus_text)
        state = fi.run(g_enhanced_instance)
        # G_enhanced is now foundation-initialized.
        # Proceed with generate_tensors() as normal.
    """

    def __init__(self, corpus_text: str = ""):
        if not corpus_text:
            corpus_text = _load_niv_corpus()
        log.info("=" * 70)
        log.info("Foundation Initializer — ai2agi inception layer")
        log.info("Source corpus: NIV Scripture (embedded)")
        log.info("=" * 70)

        self.embedder   = ScriptureEmbedder(embed_dim=EMBED_DIM)
        self.classifier = MoralPassageClassifier()
        self.loader     = ScriptureCorpusLoader(corpus_text)

        self.mq_seeder  = MQFoundationSeeder(self.embedder, self.classifier)
        self.tb_seeder  = TBFoundationSeeder()
        self.hks_seeder = HKSFoundationSeeder()

        log.info(f"Corpus loaded: {len(self.loader.books)} books, "
                 f"{len(self.loader.passages)} passages.")

    def run(self, g_enhanced_instance) -> FoundationState:
        """
        Execute full inception-layer initialization.

        1. Seed MQ  — build moral reference centroids from NIV corpus
        2. Seed TB  — pre-bind Scripture passages into SymbolicMemory
        3. Seed HKS — pre-construct knowledge graph root from Scripture

        Args:
            g_enhanced_instance: initialized GEnhanced object (from g_enhanced.py)

        Returns:
            FoundationState — carries all seeded reference data
        """
        log.info("\n── Step 1: MQ Foundation ─────────────────────────────────")
        mq_reference = self.mq_seeder.seed(self.loader.passages)

        log.info("\n── Step 2: TB Foundation ─────────────────────────────────")
        sampled_passages = self.loader.sample_passages(n=TB_SEED_PER_BOOK)
        tb_count = self.tb_seeder.seed(
            g_enhanced_instance.sym_memory,
            sampled_passages,
        )

        log.info("\n── Step 3: HKS Foundation ────────────────────────────────")
        nodes_before = g_enhanced_instance.cont_learner.hks.graph.number_of_nodes()
        self.hks_seeder.seed(g_enhanced_instance.cont_learner.hks)
        nodes_after  = g_enhanced_instance.cont_learner.hks.graph.number_of_nodes()

        state = FoundationState(
            mq_reference      = mq_reference,
            mq_seeder         = self.mq_seeder,
            tb_passages_bound = tb_count,
            hks_nodes_added   = nodes_after - nodes_before,
            dimension_counts  = self.mq_seeder.dimension_counts,
        )

        log.info("\n── Foundation Initialization Complete ────────────────────")
        log.info(f"  MQ reference shape:    {state.mq_reference.shape}")
        log.info(f"  TB passages bound:     {state.tb_passages_bound}")
        log.info(f"  HKS nodes added:       {state.hks_nodes_added}")
        log.info(f"  MQ dimension coverage: "
                 f"{state.dimension_counts}")
        log.info("=" * 70)
        log.info("G_enhanced is foundation-initialized.")
        log.info("Proceed with generate_tensors().")
        log.info("=" * 70)

        return state


# ─────────────────────────────────────────────────────────────────────────────
# RUNTIME MQ SCORER  —  integrates with G_enhanced.MultipleIntelligences
# ─────────────────────────────────────────────────────────────────────────────

def compute_scripture_mq(task_description: str,
                          foundation_state: FoundationState) -> float:
    """
    Runtime MQ scoring function.
    Called inside G_enhanced.MultipleIntelligences.update() to replace
    the default proxy with the Scripture-anchored reference score.

    Args:
        task_description:  str — description or label of current task
        foundation_state:  FoundationState from FoundationInitializer.run()

    Returns:
        MQ_score ∈ [0, 1]
    """
    return foundation_state.mq_seeder.score(task_description)


# ─────────────────────────────────────────────────────────────────────────────
# FOUNDATION VERIFICATION  —  called inside g_enhanced.py generate_tensors()
# ─────────────────────────────────────────────────────────────────────────────

class FoundationNotInitializedError(RuntimeError):
    """
    Raised when generate_tensors() is called on a GEnhanced instance
    that has not been initialized by FoundationInitializer.run().

    Resolution:
        fi = FoundationInitializer(corpus_text)
        state = fi.run(g_enhanced_instance)
        # Then call generate_tensors() normally.
    """
    pass


def verify_foundation(g_enhanced_instance) -> None:
    """
    Verifies that FoundationInitializer.run() has been executed against
    this GEnhanced instance before generate_tensors() proceeds.

    Two checks — both must pass:

    Check 1 — HKS root node present:
        HierarchicalKnowledgeStructure.graph must contain
        node 'root::Scripture' at level=0.
        This node is only added by HKSFoundationSeeder.seed().
        Its absence means the HKS was never foundation-initialized.

    Check 2 — TB pre-episode bindings present:
        SymbolicMemory.memory must contain at least one embedding
        bound with episode_id = -1 (the pre-episode marker set
        exclusively by TBFoundationSeeder.seed()).
        Its absence means TB was never foundation-initialized.

    Honest limitation (documented per architecture spec):
        These checks verify that the Foundation Initializer RAN —
        not that the corpus used was faithful or complete.
        Corpus integrity is governed by IP documentation and the
        2026 ai2agi research paper specification, not by this function.

    Args:
        g_enhanced_instance: GEnhanced object prior to generate_tensors()

    Raises:
        FoundationNotInitializedError — if either check fails.
    """

    # ── Check 1: HKS root node ────────────────────────────────────────
    hks_graph = g_enhanced_instance.cont_learner.hks.graph
    ROOT_NODE = "root::Scripture"

    if not hks_graph.has_node(ROOT_NODE):
        raise FoundationNotInitializedError(
            "\n\n"
            "════════════════════════════════════════════════════════════\n"
            "  FOUNDATION NOT INITIALIZED — ai2agi Architecture Violation\n"
            "════════════════════════════════════════════════════════════\n"
            "  generate_tensors() requires FoundationInitializer.run()\n"
            "  to be called before any tensor generation.\n\n"
            "  HKS Check FAILED: 'root::Scripture' node not found.\n"
            "  The Hierarchical Knowledge Structure has not been\n"
            "  seeded from the NIV Scripture corpus at inception.\n\n"
            "  Resolution:\n"
            "    from foundation_initializer import FoundationInitializer\n"
            "    fi = FoundationInitializer(corpus_text)\n"
            "    state = fi.run(this_g_enhanced_instance)\n\n"
            "  Reference: foundation_initializer.py — ai2agi, Ai70000 Ltd.\n"
            "  Author: Alex Osterneck, CLA, MSCS, MSIT\n"
            "════════════════════════════════════════════════════════════\n"
        )

    # ── Check 2: TB pre-episode bindings ──────────────────────────────
    tb_memory = g_enhanced_instance.sym_memory
    pre_episode_labels = [
        label for label in tb_memory.semantic_labels
        if "::p" in label and tb_memory.semantic_labels.index(label) >= 0
    ]
    # Definitive check: any label bound before episodes carries book::domain::p pattern
    # seeded exclusively by TBFoundationSeeder with episode_id = -1
    foundation_labels = [
        label for label in tb_memory.semantic_labels
        if "::" in label and not label.startswith("generic")
        and not label.startswith("task_")
        and not label.startswith("generalization")
        and not label.startswith("meta")
        and not label.startswith("few_shot")
        and not label.startswith("continual")
    ]

    if len(foundation_labels) == 0:
        raise FoundationNotInitializedError(
            "\n\n"
            "════════════════════════════════════════════════════════════\n"
            "  FOUNDATION NOT INITIALIZED — ai2agi Architecture Violation\n"
            "════════════════════════════════════════════════════════════\n"
            "  generate_tensors() requires FoundationInitializer.run()\n"
            "  to be called before any tensor generation.\n\n"
            "  TB Check FAILED: No pre-episode Scripture bindings found\n"
            "  in SymbolicMemory. Time-Binding has not been seeded\n"
            "  from the NIV Scripture corpus at inception.\n\n"
            "  Resolution:\n"
            "    from foundation_initializer import FoundationInitializer\n"
            "    fi = FoundationInitializer(corpus_text)\n"
            "    state = fi.run(this_g_enhanced_instance)\n\n"
            "  Reference: foundation_initializer.py — ai2agi, Ai70000 Ltd.\n"
            "  Author: Alex Osterneck, CLA, MSCS, MSIT\n"
            "════════════════════════════════════════════════════════════\n"
        )

    # ── Both checks passed ────────────────────────────────────────────
    log.info("verify_foundation() PASSED — HKS and TB foundation confirmed.")
    log.info(f"  HKS root node '{ROOT_NODE}' present.")
    log.info(f"  TB foundation labels: {len(foundation_labels)} bindings confirmed.")


